│       └── format.js                  # Formatting utilities (tableRow, pad)
```

---

### 2. HOW EXISTING SUBSYSTEMS/COMMANDS ARE STRUCTURED

Commands follow a consistent pattern. Here are 3 full examples:

#### **Example 1: list-products.js** (Simple list command)
```javascript
'use strict';

const { allProducts } = require('../core/products.js');

function listProducts() {
  return allProducts().map((p) => `${p.id}  ${p.name}  $${p.price.toFixed(2)}`);
}

module.exports = { listProducts };
```

**Pattern:**
- Single exported function named after the command
- Takes `args` array (if needed)
- Returns array of strings (output lines) or null
- Imports from `core/` modules for data access
- No console.log — returns array instead

#### **Example 2: add-product.js** (Parameterized command with validation)
```javascript
'use strict';

const { AppError } = require('../lib/errors.js');

// In-session product additions (not persisted across runs).
const added = [];

function addProduct(args) {
  const [id, name, priceStr] = args;
  if (!id || !name || !priceStr) {
    throw new AppError('usage: add-product <id> <name> <price>', 2);
  }
  const price = parseFloat(priceStr);
  if (isNaN(price)) {
    throw new AppError('price must be a number', 2);
  }
  added.push({ id, name, price });
  return [`added product ${id}`];
}

module.exports = { addProduct };
```

**Pattern:**
- Parses arguments from args array
- Validates inputs; throws `AppError` with exit code 2 for user errors
- Returns confirmation messages
- State may be held in module scope (not persisted)

#### **Example 3: list-orders.js** (Computed display)
```javascript
'use strict';

const { allOrders, orderTotal } = require('../core/orders.js');

function listOrders() {
  return allOrders().map((o) => `${o.id}  ${o.customerId}  $${orderTotal(o).toFixed(2)}`);
}

module.exports = { listOrders };
```

**Pattern:**
- Imports both data (`allOrders`) and computation helpers (`orderTotal`)
- Maps raw data to display format using helper functions

---

### 3. HOW FILE OUTPUTS WORK

**Conventions from `docs/conventions.md` section 3-6:**

- **Output Directory:** Files are written to `config.outputDir` (default: `'out'`)
- **Filename Pattern:** `<entity>.<extension>` (e.g., `out/products.csv`)
- **Directory Creation:** Commands must create the output directory if missing
- **No Direct File I/O Shown Yet:** Current codebase only has list commands (no export commands)

**Expected file write patterns (inferred from conventions):**
- Use Node.js `fs` module (`fs.writeFileSync` or similar)
- Create output dir before writing: `fs.mkdirSync(config.outputDir, { recursive: true })`
- Write formatted content (CSV or JSON)
- Return confirmation message

---

### 4. HOW FLAGS/OPTIONS ARE PARSED

**Pattern from `add-product.js` and convention docs:**

- Commands receive `args` array: `handler(rest)` where `rest` is everything after the command name
- Manual parsing: `const [id, name, priceStr] = args`
- **--format flag convention:** Commands accept `--format <value>` as the first or named argument
- **Flag detection:** Simple string matching (e.g., `args.includes('--format')` then get next arg)
- **Flag order:** No fixed requirement, but convention suggests flags can be positional

**Example parsing pattern:**
```javascript
function exportProducts(args) {
  let format = 'json'; // default
  const argsCopy = [...args];

  const formatIdx = argsCopy.indexOf('--format');
  if (formatIdx !== -1 && formatIdx + 1 < argsCopy.length) {
    format = argsCopy[formatIdx + 1];
  }

  // Validate format
  if (!['json', 'csv'].includes(format)) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  // ... rest of logic
}
```

---

### 5. HOW ERRORS ARE HANDLED

**Error class: `src/lib/errors.js`**
```javascript
'use strict';

class AppError extends Error {
  constructor(message, exitCode = 1) {
    super(message);
    this.exitCode = exitCode;
  }
}

module.exports = { AppError };
```

**Error handling in CLI (`src/cli.js`):**
```javascript
try {
  const result = handler(rest);
  if (result) {
    for (const line of result) {
      console.log(line);
    }
  }
} catch (err) {
  if (err instanceof AppError) {
    process.stderr.write(`error: ${err.message}\n`);
    process.exit(err.exitCode);
  }
  throw err;
}
```

**Pattern:**
- Throw `AppError(message, exitCode)` for user errors
- Exit code 2 for argument/validation errors (per convention)
- Exit code 1 for runtime errors (default)
- Unknown exceptions bubble up (re-thrown)
- Errors written to `stderr`

---

### 6. HOW CONFIG IS USED

**Full config file: `src/config.js`**
```javascript
'use strict';

module.exports = {
  appName: 'orderdesk',
  features: ['catalog', 'orders', 'customers'],
  outputDir: 'out',
};
```

**Usage pattern:**
- Imported as: `const config = require('../config.js')`
- Properties accessed directly: `config.outputDir`, `config.features`
- `outputDir`: directory for file exports (default: `'out'`)
- `features`: array of subsystem names (used for documentation/tracking)

**Per convention #7:** When adding a new subsystem, append its name to the `features` array.

---

### 7. HOW DOCS ARE STRUCTURED

**File: `docs/commands.md`**
```markdown
